// /frontend/src/components/Community.jsx
import React, { useEffect, useMemo, useState } from "react";
import api from "../lib/communityApi";

const cls = (...a) => a.filter(Boolean).join(" ");

function useAsync(fn, deps = []) {
  const [data, setData] = useState(null);
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  useEffect(() => {
    let abort = false;
    (async () => {
      try {
        setLoading(true);
        setErr("");
        const d = await fn();
        if (!abort) setData(d);
      } catch (e) {
        if (!abort) setErr(String(e?.message || e));
      } finally {
        if (!abort) setLoading(false);
      }
    })();
    return () => { abort = true; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);
  return { data, err, loading, setData };
}

export default function Community({ city = "" }) {
  const [cursor, setCursor] = useState("");
  const [limit] = useState(20);

  const { data, err, loading, setData } = useAsync(
    () => api.list({ city, limit, cursor }),
    [city, limit, cursor]
  );

  const items = useMemo(() => Array.isArray(data?.items) ? data.items : [], [data]);

  async function handleCreate(text) {
    const body = { city, text: text.trim() };
    if (!body.text) return;
    // optimistic add
    const temp = { id: `tmp-${Date.now()}`, city, text: body.text, likes: 0, replies: [], created_at: Date.now()/1000 };
    setData((prev) => ({ ...(prev || {}), items: [temp, ...(prev?.items || [])] }));
    try {
      const saved = await api.create(body);
      setData((prev) => ({
        ...(prev || {}),
        items: [saved, ...(prev?.items || []).filter(i => i.id !== temp.id)],
      }));
    } catch (e) {
      // rollback on error
      setData((prev) => ({ ...(prev || {}), items: (prev?.items || []).filter(i => i.id !== temp.id) }));
      alert(e.message || "Create failed");
    }
  }

  async function handleLike(q) {
    try {
      await api.like({ id: q.id, type: "question" });
      setData((prev) => ({
        ...(prev || {}),
        items: (prev?.items || []).map(i => i.id === q.id ? { ...i, likes: (i.likes || 0) + 1 } : i),
      }));
    } catch (e) {
      alert(e.message || "Like failed");
    }
  }

  async function handleReply(q, text) {
    const body = { questionId: q.id, text: text.trim() };
    if (!body.text) return;
    // optimistic
    const tmp = { id: `tmp-r-${Date.now()}`, text: body.text, created_at: Date.now()/1000 };
    setData((prev) => ({
      ...(prev || {}),
      items: (prev?.items || []).map(i => i.id === q.id ? { ...i, replies: [tmp, ...(i.replies || [])] } : i),
    }));
    try {
      const saved = await api.reply(body);
      setData((prev) => ({
        ...(prev || {}),
        items: (prev?.items || []).map(i => i.id === q.id
          ? { ...i, replies: [saved, ...(i.replies || []).filter(r => r.id !== tmp.id)] }
          : i),
      }));
    } catch (e) {
      // rollback
      setData((prev) => ({
        ...(prev || {}),
        items: (prev?.items || []).map(i => i.id === q.id
          ? { ...i, replies: (i.replies || []).filter(r => r.id !== tmp.id) }
          : i),
      }));
      alert(e.message || "Reply failed");
    }
  }

  async function handleReport(q) {
    const reason = prompt("Reason for report?");
    if (!reason) return;
    try {
      await api.report({ type: "question", id: q.id, reason });
      alert("Reported. Thank you.");
    } catch (e) {
      alert(e.message || "Report failed");
    }
  }

  return (
    <div className="space-y-4 text-white">
      <Composer onSubmit={handleCreate} city={city} />

      {loading && <div className="text-sm opacity-80">Loading community…</div>}
      {err && <div className="text-sm text-red-300">{err}</div>}

      <div className="space-y-3">
        {items.map((q) => (
          <QuestionCard
            key={q.id}
            q={q}
            onLike={() => handleLike(q)}
            onReply={(text) => handleReply(q, text)}
            onReport={() => handleReport(q)}
          />
        ))}
        {!loading && !items.length && (
          <div className="rounded-2xl bg-black/30 backdrop-blur p-4 text-sm opacity-90">
            No posts yet{city ? ` in ${city}` : ""}. Be the first to ask something!
          </div>
        )}
      </div>

      {data?.next_cursor && (
        <div className="pt-1">
          <button
            onClick={() => setCursor(data.next_cursor)}
            className="px-3 py-2 rounded-lg bg-white/15 hover:bg-white/25 transition text-sm"
          >
            Load more
          </button>
        </div>
      )}
    </div>
  );
}

function Composer({ onSubmit, city }) {
  const [text, setText] = useState("");
  function send(e) {
    e.preventDefault();
    onSubmit?.(text);
    setText("");
  }
  return (
    <form onSubmit={send} className="rounded-2xl bg-black/30 backdrop-blur p-4">
      <div className="font-semibold mb-2">Start a discussion {city ? `in ${city}` : ""}</div>
      <div className="flex gap-2">
        <input
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Ask a weather question…"
          className="flex-1 px-3 py-2 rounded-lg bg-white/10 outline-none text-white placeholder-white/70"
        />
        <button className="px-3 py-2 rounded-lg bg-purple-600 text-white">Post</button>
      </div>
    </form>
  );
}

function QuestionCard({ q, onLike, onReply, onReport }) {
  const [open, setOpen] = useState(false);
  const [rtext, setRtext] = useState("");

  return (
    <article className="rounded-2xl bg-black/30 backdrop-blur p-4">
      <header className="flex items-center justify-between">
        <div className="font-medium">{q.city || "Somewhere"}</div>
        <time className="text-xs opacity-70">
          {q.created_at ? new Date((q.created_at*1000) || Date.now()).toLocaleString() : ""}
        </time>
      </header>
      <p className="mt-1">{q.text}</p>

      <div className="mt-3 flex items-center gap-3">
        <button onClick={onLike} className="px-2 py-1 rounded bg-white/10 hover:bg-white/20 text-sm">
          👍 {q.likes ?? 0}
        </button>
        <button onClick={() => setOpen((v) => !v)} className="px-2 py-1 rounded bg-white/10 hover:bg-white/20 text-sm">
          💬 {q.replies?.length ?? 0}
        </button>
        <button onClick={onReport} className="px-2 py-1 rounded bg-white/10 hover:bg-white/20 text-sm">
          🚩 Report
        </button>
      </div>

      {open && (
        <div className="mt-3 space-y-2">
          <form
            onSubmit={(e) => { e.preventDefault(); onReply?.(rtext); setRtext(""); }}
            className="flex gap-2"
          >
            <input
              value={rtext}
              onChange={(e) => setRtext(e.target.value)}
              placeholder="Write a reply…"
              className="flex-1 px-3 py-2 rounded-lg bg-white/10 outline-none text-white placeholder-white/70"
            />
            <button className="px-3 py-2 rounded-lg bg-purple-600 text-white">Reply</button>
          </form>

          <div className="space-y-1">
            {(q.replies || []).map((r) => (
              <div key={r.id} className="px-3 py-2 rounded-lg bg-white/5 text-sm">
                <div className="opacity-90">{r.text}</div>
                <div className="text-xs opacity-70 mt-1">
                  {r.created_at ? new Date((r.created_at*1000) || Date.now()).toLocaleString() : ""}
                </div>
              </div>
            ))}
            {!q.replies?.length && <div className="text-xs opacity-70">No replies yet.</div>}
          </div>
        </div>
      )}
    </article>
  );
}
